const MAIN_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_BASE_PREMIUM = 25;

function isComponent(item: Item): boolean {
  return COMPONENT_TYPES.has(item.type);
}

function isMainItem(item: Item): boolean {
  return item.type in MAIN_BASE_PREMIUMS;
}

function mainItemBasePremium(item: Item): number {
  return MAIN_BASE_PREMIUMS[item.type];
}

function componentsBasePremium(items: Item[]): number {
  // Group by component type and apply block discount where exactly 3 of a type
  const counts = new Map<string, number>();
  for (const it of items) {
    counts.set(it.type, (counts.get(it.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    total += count * COMPONENT_BASE_PREMIUM;
  }
  return total;
}

function policyBasePremium(items: Item[]): number {
  const mains = items.filter(isMainItem);
  const comps = items.filter(isComponent);
  const mainSum = mains.reduce((s, it) => s + mainItemBasePremium(it), 0);
  return mainSum + componentsBasePremium(comps);
}

function itemPremiumWithModifiers(item: Item): number {
  if (isMainItem(item)) return mainItemBasePremium(item);
  return 0; // components handled in aggregate
}

function quotePremium(items: Item[]): number {
  const policyBase = policyBasePremium(items);
  const mains = items.filter(isMainItem);
  const comps = items.filter(isComponent);
  const mainsModified = mains.reduce((s, it) => s + itemPremiumWithModifiers(it), 0);
  const compsBase = componentsBasePremium(comps);
  const itemsTotal = mainsModified + compsBase;
  const firstInsurance = policyBase * 0.1;
  const total = itemsTotal + firstInsurance;
  return Math.ceil(total + 5);
}

